                            mvaddch(columns[x], x, alpha[rand() % ALPHA_SIZE]);
                        }
                    }
                    columns[x]++;
                }
            }

            if (columns[x] >= maxy + 20) {
                columns[x] = 0;
            }
        }

        if (screensaver) {
            int ch = getch();
            if (ch != ERR) break;
        }

        refresh();
        usleep(50000 / (delay + 1));
        i++;
    }

    endwin();
    return 0;
}
